import{_ as r,o as a,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-02.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-02.md"}'),l={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-02.md"};function i(n,t,s,d,g,h){return a(),e("div",null,[...t[0]||(t[0]=[o('<p>🫘 黃豆追蹤日報 — 2026年6月2日（週二）</p><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-06-02 05:00 = 2026-06-01 21:00 UTC) <strong>昨日敘事延續</strong>：伊朗暫停和談 → 荷莫茲封鎖升級 → 油價暴漲 6% → CBOT 黃豆 1,182-1,187 區間 → 種植進度 87% 超前 → 聖嬰預警持續 → COMPUTEX 本週開幕</p></blockquote><hr><h2 id="📊-8項指標檢查" tabindex="-1">📊 8項指標檢查 <a class="header-anchor" href="#📊-8項指標檢查" aria-label="Permalink to &quot;📊 8項指標檢查&quot;">​</a></h2><h3 id="指標1️⃣-usda-種植進度報告-—-🔴-本週更新-種植-87-首份作物條件出爐" tabindex="-1">指標1️⃣ USDA 種植進度報告 — 🔴 本週更新！種植 87%，首份作物條件出爐 <a class="header-anchor" href="#指標1️⃣-usda-種植進度報告-—-🔴-本週更新-種植-87-首份作物條件出爐" aria-label="Permalink to &quot;指標1️⃣ USDA 種植進度報告 — 🔴 本週更新！種植 87%，首份作物條件出爐&quot;">​</a></h3><p><strong>最新數據（6/1 公布，截至 5/31）</strong>：</p><ul><li><strong>黃豆種植完成度：87%</strong>（5年平均 68%，去年 76%）— <strong>超前 19 個百分點</strong></li><li><strong>出芽率：65%</strong></li><li><strong>首份作物條件評級：66% good-to-excellent</strong></li><li><strong>前週（5/24）</strong>：79%（5年平均 53%）</li><li><strong>一週推進</strong>：+8 個百分點</li></ul><p><strong>與昨日比較</strong>：🔴 <strong>重大更新</strong> — 本週 6/1 公布的 Crop Progress 報告顯示：</p><ol><li>種植進度從 79% → 87%，持續大幅超前</li><li><strong>首份作物條件評級出爐</strong>：66% good-to-excellent，為本季首次</li><li>出芽率 65%，健康成長</li><li>Michigan 仍相對落後（37% → 預估 ~50%），其餘各州均已超過 80%</li></ol><p><strong>影響分析</strong>：</p><ul><li>種植超前 + 條件良好 → 預期供給寬鬆 → 價格壓力</li><li>但荷莫茲封鎖 → 化肥/運輸成本上升 → 成本支撐</li><li>市場在「供給寬鬆」vs「成本上升」間拉鋸</li></ul><p>📎 來源：<a href="https://www.brownfieldagnews.com/news/67-of-u-s-corn-66-of-soybeans-rated-good-to-excellent-2/" target="_blank" rel="noreferrer">Brownfield Ag News</a> · <a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/06/01/crop-progress-corn-93-planted-67-87" target="_blank" rel="noreferrer">DTN/PF</a> （TST 05:00）</p><hr><h3 id="指標2️⃣-巴西供應-—-🟢-豐收紀錄持續-出口創歷史新高" tabindex="-1">指標2️⃣ 巴西供應 — 🟢 豐收紀錄持續，出口創歷史新高 <a class="header-anchor" href="#指標2️⃣-巴西供應-—-🟢-豐收紀錄持續-出口創歷史新高" aria-label="Permalink to &quot;指標2️⃣ 巴西供應 — 🟢 豐收紀錄持續，出口創歷史新高&quot;">​</a></h3><p><strong>巴西 2025/26 年度</strong>：</p><ul><li><strong>產量預估</strong>：172.5-186 百萬噸（各家差異大） <ul><li>Conab：176.9 百萬噸（+4% YoY）</li><li>Hedgepoint：181 百萬噸</li><li>CERA：184 百萬噸（歷史新高，+7% YoY）</li><li>USDA（2026/27）：186 百萬噸</li></ul></li><li><strong>出口</strong>： <ul><li>Conab 預測 2026 年出口 116 百萬噸</li><li>Terra Investimentos：117 百萬噸（歷史新高，2025 年 108 百萬噸）</li><li><strong>截至 5 月已出口 51.6 百萬噸</strong>，超越 2025 同期</li></ul></li><li><strong>挑戰</strong>：港口攤塞、卡車運輸效率低（僅 14% 公路鋪設）、國內壓榨需求增加（生質柴油）</li></ul><p><strong>與昨日比較</strong>：無重大變化。巴西豐收紀錄持續壓制國際價格上行空間。</p><p>📎 來源：<a href="https://farmdocdaily.illinois.edu/2026/03/brazil-heads-for-a-record-soybean-harvest-as-farm-margins-approach-breakeven.html" target="_blank" rel="noreferrer">farmdocdaily.illinois.edu</a> · <a href="https://www.czapp.com/analyst-insights/global-soybean-market-set-for-further-growth-in-2026-27/" target="_blank" rel="noreferrer">CZApp</a> （TST 05:00）</p><hr><h3 id="指標3️⃣-尿素價格-多單訊號-—-🟡-從高點大幅修正後穩定" tabindex="-1">指標3️⃣ 尿素價格 + 多單訊號 — 🟡 從高點大幅修正後穩定 <a class="header-anchor" href="#指標3️⃣-尿素價格-多單訊號-—-🟡-從高點大幅修正後穩定" aria-label="Permalink to &quot;指標3️⃣ 尿素價格 + 多單訊號 — 🟡 從高點大幅修正後穩定&quot;">​</a></h3><p><strong>最新報價（6/1）</strong>：</p><ul><li>TradingEconomics 全球尿素指數：~$446-$453/噸</li><li>Barchart.com 美國海灣 FOB 6月期貨（JCM26）：$451.00</li><li><strong>3月高峰</strong>：$725.6/噸（荷莫茲危機）→ 現在 $446 → <strong>修正幅度 -39%</strong></li><li><strong>世界銀行警告</strong>：2026 年全球化肥價格可能上漲 30% 以上</li><li>AgEcon：在「有爭議運輸」情境下，7月 NOLA 批發尿素可能達 $784/短噸</li></ul><p><strong>與昨日比較</strong>：無重大變化。尿素穩定在 $446-453 區間，從封鎖高峰大幅修正。</p><p><strong>對黃豆影響</strong>：</p><ul><li>尿素從 $725 → $446 → 種植成本壓力有所緩解</li><li>但荷莫茲封鎖持續 → 化肥供應風險仍存 → 價格可能再度波動</li><li>伊朗暫停和談 → 封鎖升級預期 → 化肥價格可能再度上行</li></ul><p>📎 來源：<a href="https://tradingeconomics.com/commodity/urea" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://www.barchart.com/futures/quotes/JCM26" target="_blank" rel="noreferrer">Barchart</a> · <a href="https://cavinresource.com/de/urea-fertilizer-price/" target="_blank" rel="noreferrer">CavinResource</a> （TST 05:00）</p><hr><h3 id="指標4️⃣-荷莫茲海峽通航狀態-—-🔴-封鎖升級-伊朗暫停和談" tabindex="-1">指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 封鎖升級！伊朗暫停和談 <a class="header-anchor" href="#指標4️⃣-荷莫茲海峽通航狀態-—-🔴-封鎖升級-伊朗暫停和談" aria-label="Permalink to &quot;指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 封鎖升級！伊朗暫停和談&quot;">​</a></h3><p><strong>6/1 最新動態</strong>：</p><ul><li><strong>伊朗 IRGC 暫停與美國的和平談判</strong></li><li><strong>伊朗威脅全面封鎖荷莫茲海峽 + 啟用 Bab el-Mandeb 替代路線</strong></li><li><strong>實際通航</strong>：~23 艘/日（戰前 125-140 艘/日），<strong>恢復率僅 16-18%</strong></li><li><strong>美國 CENTCOM</strong>：過去 3 週引導 ~70 艘商船通過</li><li><strong>伊朗 IRGC</strong>：過去 24 小時协调 15 艘船通過（含 4 艘油輪）</li><li><strong>沙烏地阿拉伯、UAE</strong>：已改用替代出口路線</li><li><strong>阿曼</strong>：受惠維持出口量 + 高油價</li><li><strong>美國封鎖伊朗港口</strong>：伊朗石油出口大幅減少 → 多餘產能被迫儲存</li></ul><p><strong>與昨日比較</strong>：🔴 <strong>重大惡化</strong> — 昨日（6/1）Trump 拒絕原始 MoU 送出第3輪修改 → 今日伊朗直接暫停和談。升級速度超預期。</p><p><strong>對黃豆影響</strong>：</p><ul><li>封鎖升級 → 化肥供應緊繃 → 種植成本壓力回升</li><li>運輸中斷 → 全球糧食供應鏈風險 → 避險需求</li><li>油價暴漲 6% → 運輸成本上升 → 黃豆到岸價上漲</li></ul><p>📎 來源：<a href="https://www.icis.com/explore/resources/news/2026/06/01/11213139/transits-through-strait-of-hormuz-remain-limited-as-iran-us-peace-talks-fizzle/" target="_blank" rel="noreferrer">ICIS</a> · <a href="https://www.cbsnews.com/live-updates/iran-war-us-trump-strikes-ceasefire-lebanon-israel/" target="_blank" rel="noreferrer">CBS News</a> · <a href="https://www.worldoil.com/news/2026/6/1/oil-jumps-after-report-iran-suspends-communications-with-u-s/" target="_blank" rel="noreferrer">WorldOil</a> （TST 05:00）</p><hr><h3 id="指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距-無新進展" tabindex="-1">指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距（無新進展） <a class="header-anchor" href="#指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距-無新進展" aria-label="Permalink to &quot;指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距（無新進展）&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li>中國承諾 2026-28 年每年至少購買 2,500 萬噸美國黃豆</li><li>白宮事實清單：中國將額外購買每年至少 $170 億美元美國農產品</li><li>2026年前兩個月美國對中黃豆出口 +79.66%</li><li><strong>但</strong>：2025年3月至2026年2月，美國對中農產品出口下降 $149 億（黃豆佔一半）</li><li><strong>關稅影響</strong>：中國對美黃豆仍維持 10% 附加關稅（+10% 基準關稅 = 20% 差異）</li><li><strong>中國 PMI 5月</strong>：50.0（險守榮枯線）— 經濟復甦放緩</li></ul><p><strong>與昨日比較</strong>：無新進展。北京仍未正式確認承諾金額。中國 PMI 從 50.3 降至 50.0，需求端壓力增加。</p><p>📎 來源：<a href="https://www.scmp.com/economy/global-economy/article/3353803/soybean-counters-scope-china-us-farm-deal-depends-math-analysts-say" target="_blank" rel="noreferrer">SCMP</a> · <a href="https://farmpolicynews.illinois.edu/2026/05/chinas-retaliatory-tariffs-cost-us-ag-exporters-15-billion-study-says/" target="_blank" rel="noreferrer">Farm Policy News</a> （TST 05:00）</p><hr><h3 id="指標6️⃣-天然氣價格-—-🟡-間接受荷莫茲影響" tabindex="-1">指標6️⃣ 天然氣價格 — 🟡 間接受荷莫茲影響 <a class="header-anchor" href="#指標6️⃣-天然氣價格-—-🟡-間接受荷莫茲影響" aria-label="Permalink to &quot;指標6️⃣ 天然氣價格 — 🟡 間接受荷莫茲影響&quot;">​</a></h3><ul><li><strong>荷莫茲封鎖</strong> → 中東天然氣出口受影響 → 全球 LNG 供應緊張</li><li><strong>歐洲天然氣</strong>：受荷莫茲影響，TTF 價格可能再度走高</li><li><strong>美國 Henry Hub</strong>：相對穩定，但出口需求可能增加</li><li><strong>對黃豆</strong>：天然氣是尿素生產的主要原料 → 天然氣價格上行 → 尿素成本上升 → 黃豆種植成本上升</li></ul><p><strong>與昨日比較</strong>：無重大變化。荷莫茲封鎖升級可能進一步推高天然氣價格。</p><p>📎 來源：<a href="https://tradingeconomics.com/commodity/natural-gas" target="_blank" rel="noreferrer">TradingEconomics</a> （TST 05:00）</p><hr><h3 id="指標7️⃣-聖嬰-拉尼娜氣候風險-—-🟡-聖嬰概率上升中" tabindex="-1">指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🟡 聖嬰概率上升中 <a class="header-anchor" href="#指標7️⃣-聖嬰-拉尼娜氣候風險-—-🟡-聖嬰概率上升中" aria-label="Permalink to &quot;指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🟡 聖嬰概率上升中&quot;">​</a></h3><p><strong>最新預測</strong>：</p><ul><li>NOAA CPC：2026 年聖嬰（El Niño）<strong>高度可能在未來數月形成</strong></li><li>預計持續至 2026-27 年北半球冬季</li><li><strong>強聖嬰概率</strong>：~33%（10-12月可能達「非常強」等級）</li><li><strong>對美國黃豆</strong>：歷史模式顯示聖嬰通常有利美國中西部降雨 → 產量可能提升</li><li><strong>對巴西</strong>：聖嬰可能帶來有利降雨 → 但供給已處紀錄高位</li><li><strong>全球影響</strong>：聖嬰通常導致印尼、馬來西亞、印度、澳洲乾旱 → 農產品供應緊張</li><li><strong>延遲效應</strong>：強聖嬰事件的供給影響通常滯後 → 可能導致 2027-28 全球農產品緊張</li></ul><p><strong>與昨日比較</strong>：無重大變化。聖嬰概率持續上升，中長期影響需持續追蹤。</p><p>📎 來源：<a href="https://www.cpc.ncep.noaa.gov/products/analysis_monitoring/lanina/enso_evolution-status-fcsts-web.pdf" target="_blank" rel="noreferrer">NOAA CPC</a> · <a href="https://www.farmprogress.com/marketing/how-el-nino-could-help-farmers-outyield-high-production-costs" target="_blank" rel="noreferrer">FarmProgress</a> （TST 05:00）</p><hr><h3 id="指標8️⃣-cbot-價格區間-—-🟡-穩定在-11-80-11-87" tabindex="-1">指標8️⃣ CBOT 價格區間 — 🟡 穩定在 $11.80-$11.87 <a class="header-anchor" href="#指標8️⃣-cbot-價格區間-—-🟡-穩定在-11-80-11-87" aria-label="Permalink to &quot;指標8️⃣ CBOT 價格區間 — 🟡 穩定在 $11.80-$11.87&quot;">​</a></h3><p><strong>最新報價（6/1）</strong>：</p><ul><li><strong>CBOT 黃豆 July 2026（ZSN26）</strong>： <ul><li>Barchart：$11.82 6/8（-0.34%）</li><li>CME Group：$11.86 4/8（-8&#39; from prior settle）</li><li>Farmbucks：$11.8675（-0.65%）</li><li>TradingEconomics：$11.8092/Bu（-0.49%）</li><li>Pro Farmer：$11.80 3/4（-5 cents）</li></ul></li><li><strong>豆油</strong>：再創合約新高（+39 points overnight）</li><li><strong>豆粕</strong>：+$0.90</li><li><strong>區間</strong>：$11.80-$11.87/Bu</li></ul><p><strong>與昨日比較</strong>：</p><ul><li>6/1 收盤：~$11.82-$11.87（小幅下跌 0.3-0.65%）</li><li>6/1 overnight：+5.25 cents（反彈）</li><li><strong>今日（6/2）USDA 月度油脂報告 + 作物進度</strong>：重要催化劑</li></ul><p><strong>影響分析</strong>：</p><ul><li>種植超前 + 條件良好 → 壓力</li><li>荷莫茲封鎖升級 → 化肥/運輸成本支撐</li><li>豆油創高 → 需求端（生質柴油）支撐</li><li>市場在多空因素間拉鋸</li></ul><p>📎 來源：<a href="https://www.barchart.com/futures/quotes/zs*0/futures-prices" target="_blank" rel="noreferrer">Barchart</a> · <a href="https://www.cmegroup.com/markets/agriculture/oilseeds/soybean.quotes.html" target="_blank" rel="noreferrer">CME Group</a> · <a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://www.profarmer.com/news/first-thing-today/first-thing-today-corn-wheat-bulls-their-heels-start-june" target="_blank" rel="noreferrer">Pro Farmer</a> （TST 05:00）</p><hr><h2 id="📰-即時新聞-5條" tabindex="-1">📰 即時新聞（5條） <a class="header-anchor" href="#📰-即時新聞-5條" aria-label="Permalink to &quot;📰 即時新聞（5條）&quot;">​</a></h2><h3 id="_1-🔴-伊朗暫停美伊和談-威脅全面封鎖荷莫茲海峽" tabindex="-1">1. 🔴 伊朗暫停美伊和談，威脅全面封鎖荷莫茲海峽 <a class="header-anchor" href="#_1-🔴-伊朗暫停美伊和談-威脅全面封鎖荷莫茲海峽" aria-label="Permalink to &quot;1. 🔴 伊朗暫停美伊和談，威脅全面封鎖荷莫茲海峽&quot;">​</a></h3><p>伊朗 IRGC 暫停與美國的和平談判，主因以色列在黎巴嫩與加薩的軍事行動違反停火協議。伊朗威脅全面封鎖荷莫茲海峽並啟用 Bab el-Mandeb 替代路線。油價暴漲 6%。（來源：CBS News、Guardian，TST 05:00）</p><h3 id="_2-🔴-usda-6-1-公布種植進度-黃豆-87-首份作物條件-66-g-e" tabindex="-1">2. 🔴 USDA 6/1 公布種植進度：黃豆 87%，首份作物條件 66% G/E <a class="header-anchor" href="#_2-🔴-usda-6-1-公布種植進度-黃豆-87-首份作物條件-66-g-e" aria-label="Permalink to &quot;2. 🔴 USDA 6/1 公布種植進度：黃豆 87%，首份作物條件 66% G/E&quot;">​</a></h3><p>美國黃豆種植完成度 87%（5年平均 68%），大幅超前。首份作物條件評級 66% good-to-excellent。出芽率 65%。Michigan 仍相對落後。（來源：Brownfield Ag News、DTN/PF，TST 05:00）</p><h3 id="_3-🟡-nvidia-computex-rtx-spark-vera-rubin-40-億光子投資" tabindex="-1">3. 🟡 NVIDIA Computex RTX Spark + Vera Rubin + $40 億光子投資 <a class="header-anchor" href="#_3-🟡-nvidia-computex-rtx-spark-vera-rubin-40-億光子投資" aria-label="Permalink to &quot;3. 🟡 NVIDIA Computex RTX Spark + Vera Rubin + $40 億光子投資&quot;">​</a></h3><p>黃仁勳 GTC Taipei 發表 RTX Spark PC 晶片、Vera Rubin 架構、$40 億光子投資、Spectrum-X 409.6 Tb/s。COMPUTEX 2026 今日正式開幕。台灣光通訊族群受惠。（來源：NVIDIA、PCMag，TST 05:00）</p><h3 id="_4-🟡-anthropic-秘密提交-ipo-估值-9-650-億超越-openai" tabindex="-1">4. 🟡 Anthropic 秘密提交 IPO，估值 $9,650 億超越 OpenAI <a class="header-anchor" href="#_4-🟡-anthropic-秘密提交-ipo-估值-9-650-億超越-openai" aria-label="Permalink to &quot;4. 🟡 Anthropic 秘密提交 IPO，估值 $9,650 億超越 OpenAI&quot;">​</a></h3><p>Anthropic 6/1 正式向 SEC 秘密提交 IPO 文件。此前融資 $650 億，估值 $9,650 億。AI 產業 IPO 熱潮啟動。（來源：Guardian、Forbes，TST 05:00）</p><h3 id="_5-🟡-美股-s-p-500-nasdaq-雙創歷史新高-台股-45-337-新紀錄" tabindex="-1">5. 🟡 美股 S&amp;P 500 &amp; Nasdaq 雙創歷史新高，台股 45,337 新紀錄 <a class="header-anchor" href="#_5-🟡-美股-s-p-500-nasdaq-雙創歷史新高-台股-45-337-新紀錄" aria-label="Permalink to &quot;5. 🟡 美股 S&amp;P 500 &amp; Nasdaq 雙創歷史新高，台股 45,337 新紀錄&quot;">​</a></h3><p>S&amp;P 500 +0.5%、Nasdaq +0.7% 均創歷史新高。台股 TAIEX 45,337.91（+1.35%），首度站上 45,000。COMPUTEX + AI 熱潮驅動。（來源：CNBC、TaiwanNews，TST 05:00）</p><hr><h2 id="📊-情景分析" tabindex="-1">📊 情景分析 <a class="header-anchor" href="#📊-情景分析" aria-label="Permalink to &quot;📊 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>概率</th><th>CBOT 價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>和談破裂 + 全面封鎖</td><td>25%</td><td>$12.20-$12.80</td><td>化肥飆升 + 運輸中斷 + 通膨預期</td></tr><tr><td>和談重啟 + 部分開放</td><td>40%</td><td>$11.50-$11.80</td><td>成本壓力緩解 + 供給寬鬆主導</td></tr><tr><td>維持現狀（僵局）</td><td>35%</td><td>$11.70-$12.00</td><td>多空拉鋸，區間震盪</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>來源</th><th>查詢時間</th><th>內容</th></tr></thead><tbody><tr><td>1</td><td>Brownfield Ag News</td><td>TST 05:00</td><td>USDA 種植進度</td></tr><tr><td>2</td><td>DTN/PF</td><td>TST 05:00</td><td>作物條件評級</td></tr><tr><td>3</td><td>farmdocdaily.illinois.edu</td><td>TST 05:00</td><td>巴西豐收數據</td></tr><tr><td>4</td><td>CZApp</td><td>TST 05:00</td><td>巴西出口預測</td></tr><tr><td>5</td><td>TradingEconomics</td><td>TST 05:00</td><td>尿素價格</td></tr><tr><td>6</td><td>Barchart</td><td>TST 05:00</td><td>CBOT 黃豆期貨</td></tr><tr><td>7</td><td>ICIS</td><td>TST 05:00</td><td>荷莫茲通航</td></tr><tr><td>8</td><td>NOAA CPC</td><td>TST 05:00</td><td>聖嬰預測</td></tr><tr><td>9</td><td>SCMP</td><td>TST 05:00</td><td>中美貿易</td></tr><tr><td>10</td><td>Pro Farmer</td><td>TST 05:00</td><td>晨間市場評論</td></tr></tbody></table>',78)])])}const u=r(l,[["render",i]]);export{c as __pageData,u as default};
